mapper.select:
SELECT exists(
  SELECT name_id
  FROM name_match
  WHERE dataset_key = #{datasetKey}

  AND sector_key = #{sectorKey}

LIMIT 1
)

SELECT nm.index_id AS nidx, nm.index_id IS NOT NULL AS matched
FROM name_match nm
WHERE nm.dataset_key = #{key.datasetKey} AND nm.name_id = #{key.id}

SELECT n.id AS canonical_id
FROM name_match nm LEFT JOIN names_index n ON n.id=nm.index_id
WHERE nm.dataset_key = #{key.datasetKey} AND nm.name_id = #{key.id}

SELECT nm.index_id AS nidx, nm.index_id IS NOT NULL AS matched
FROM name_match nm
WHERE nm.dataset_key = #{key.datasetKey} AND nm.sector_key = #{key.id}

SELECT DISTINCT index_id
FROM name_match
WHERE dataset_key = #{datasetKey}

  AND sector_key = #{sectorKey}

mapper.insert:
INSERT INTO name_match (dataset_key,sector_key,index_id,name_id) SELECT #{newDatasetKey},nm.sector_key,nm.index_id,coalesce(m.id2,nm.name_id) FROM name_match nm
LEFT JOIN idmap_name_${datasetKey} m ON m.id=nm.name_id
WHERE nm.dataset_key = #{datasetKey}

mapper.select:
SELECT count(*)
FROM name_match
WHERE dataset_key = #{datasetKey}

SELECT count(*)
FROM name_match nm
WHERE nm.index_id=#{nidx}

  AND nm.dataset_key = #{datasetKey}
